from django.test import TestCase
from myapp.models import Article

class ArticleViewTest(TestCase):
    def setUp(self):
        Article.objects.create(title='A', status='published')
        Article.objects.create(title='B', status='published')
        Article.objects.create(title='C', status='published')

    def test_article_list(self):
        response = self.client.get('/articles/')
        self.assertEqual(response.status_code, 200)
        self.assertEqual(len(response.context['articles']), 3)

class ArticleDeleteTest(TestCase):
    def test_delete(self):
        article = Article.objects.create(title='D')
        response = self.client.post(f'/articles/{article.id}/delete/')
        self.assertEqual(Article.objects.count(), 0)

import unittest

class TestArticleAPI(unittest.TestCase):
    def setUp(self):
        from myapp.models import Article
        self.article = Article.objects.create(
            title='Test', body='Test body'
        )

    def test_list_articles(self):
        response = self.client.get('/api/articles/')
        self.assertEqual(response.status_code, 200)

    def test_create_article(self):
        response = self.client.post('/api/articles/', {
            'title': 'New', 'body': 'New body'
        })
        self.assertEqual(response.status_code, 201)
